#include <stdio.h>
#define MOD 1000000009
long long dp[1001][201][201];
long long solve(int n, int m, int k) {
    if (m == 0) return 1;
    if (dp[m][n][k] != -1) return dp[m][n][k];
    long long ans = 0;
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m - 1; j++) {
            if (j >= k + 1) {
                ans = (ans + solve(n - 1, m - j - 1, k)) % MOD;
            }
        }
    }
    return dp[m][n][k] = ans;
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m, k;
        scanf("%d %d %d", &n, &m, &k);
        for (int i = 0; i <= m; i++) {
            for (int j = 0; j <= n; j++) {
                for (int l = 0; l <= k; l++) {
                    dp[i][j][l] = -1;
                }
            }
        }
        printf("%lld\n", solve(n, m, k));
    }
    return 0;
}

